VALUES
  ('social-worker-moex-07640', 'social-worker', 'social-worker-moex-099-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '根據甲段文章，下列敘述不正確的選項是：', '["精妙的學問與技藝常是「雖在父兄，不能以移子弟」", "本篇的「得手應心」近於〈庖丁解牛〉中「遊刄有餘」之意", "讀書與技藝皆重於個人的自覺自證，不能只依賴別人的傳授", "輪扁說桓公讀的是糟魄，是在批評桓公讀的書太淺薄，不夠深入"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "c67fbcca8028", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07641', 'social-worker', 'social-worker-moex-099-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '根據乙段文章，下列敘述正確的選項是：', '["李公擇年少好讀書，年長就丟下九千餘卷藏書，下山去了", "李公擇讀的書「未嘗少損」，可見並未用心投入，好好研讀", "蘇東坡感嘆：古人想讀書而很難看到書，現在的人有書而不讀", "蘇東坡旅遊至廬山，發現李氏山房這一人文景點，所以寫了這篇文章"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "c67fbcca8028", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07642', 'social-worker', 'social-worker-moex-099-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '人間事理往往因觀點不同而說法不同。上述兩段材料各有不同的讀書觀點，兩段材料都有價值，問題是能 否判別情境適時活用。設想如需借用上兩段材料中的一段，分別運用在下列三種情境中：', '["為鼓勵青少年多閱讀時", "與一個食古不化的書呆子談讀書的藝術時", "某圖書館想以一則故事為徵募圖書宣傳時 各用那一段材料取義闡發較為合適？", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "c67fbcca8028", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07643', 'social-worker', 'social-worker-moex-099-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '根據上文內容判斷，下列敘述正確的選項是？', '["作者贊同史基納的行為主義學派理論", "作者大致贊同心理學家布萊爾的看法", "作者對史基納和布萊爾都有不同意見", "作者同意布萊爾但又提出修正的看法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "c67fbcca8028", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07644', 'social-worker', 'social-worker-moex-099-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列選項對文中提及動物「頓悟」的敘述，何者正確？', '["海豚能因「頓悟」完成表演正印證了史基納的行為主義學派的理論", "動物不一定需要外在的刺激獎勵才能學習，牠們本身即可學習領悟", "莫兒害怕被捕，海豚生性聰明，牠們都因畏懼負增強而當下「頓悟」", "狗和海豚因為牠們臨時得不到正增強而受刺激產生了「頓悟」的經驗"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "c67fbcca8028", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07645', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '年第一次專門職業及技術人員高等考試社會工作師考試試題 類       科：社會工作師 甲、申論題部分：（50分） 不必抄題，作答時請將試題題號及答案依照順序寫在申論試卷上，於本試題上作答者，不予計分。 請以藍、黑色鋼筆或原子筆在申論試卷上作答。', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 99, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07646', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有兒童及少年保護個案通報時，其承辦社工員應於受理案件後依「兒童及少年福利法」規定，必須於 多少時間內提出調查報告？', '["二日", "三日", "四日", "五日 社會工作心理暨社會學派的直接處遇技巧，如支持性的技術 ，乃對案主表達溫馨、"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07647', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '(sustaining procedures) 關注、感興趣和協助的意願，以及同理的傾聽、接納、確信和鼓勵，使案主可以減輕焦慮或壓力，並有 改變即將來臨的希望，請問社會工作者在會談時對案主下面的陳述如何回應（請選最適切答案）？ 案主說：「我不知道自己今天這樣做是對或錯，不過，我覺得自己似乎是正在從人群撤退。我似乎不想 和人們交往，也不再和他們玩那些愚蠢的遊戲。」', '["「像這樣的友誼實在是靠不住的。」", "「不要難過，這樣的友誼不要也罷。」", "「他們無法讓你做你真正的自己，讓你覺得十分難過。」", "「你覺得實在很難過，因為你無法做你真正的自己，或無法成為你想要的自己。你現在可以做的第一件 事情，就是花一點時間來思考如果不再和他們在一起，那麼你期待自己會變成另外什麼較好的樣子？」"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07648', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '當個人經歷重大人生角色轉變，或遭遇重大損失傷亡等變故時，下列那一種處遇理論類型或取向可能最 適合？', '["精神分析", "認知治療、理情治療或行為治療", "意義治療和完形治療", "以上皆非"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07649', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '對於社會工作的解釋，有各種不同的界說及定義，以下何者對社會工作的定義有誤？', '["是一種專業的活動", "是一種研究社會關係的科學", "是一種專業的學科", "是一種重視專業關係的助人專業"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
